prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?defaultFlow ?gwDir WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  FILTER(STRENDS(STR(?gateway), "sid-B216E792-FFDE-4AEC-AF35-317D250205B0"))
  OPTIONAL { ?gateway bboExt:default ?defaultFlow }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gwDir }
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?condition ?expression WHERE {
  ?flow a bbo:SequenceFlow .
  ?flow bbo:has_targetRef ?target .
  ?target bbo:name "Probe ausliefern" .
  OPTIONAL { ?flow bbo:condition ?condition }
  OPTIONAL { ?flow bboExt:conditionExpression ?expression }
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
